**SecurityConfig — the central piece:**
```java
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private final JwtAuthFilter jwtAuthFilter;
    private final UserDetailsService userDetailsService;

    SecurityConfig(JwtAuthFilter jwtAuthFilter, UserDetailsService uds) {
        this.jwtAuthFilter = jwtAuthFilter;
        this.userDetailsService = uds;
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        return http
            .csrf(csrf -> csrf.disable())  // disable CSRF for stateless JWT APIs
            .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/auth/**").permitAll()      // login/register: open
                .requestMatchers(HttpMethod.GET, "/api/products/**").permitAll()  // read-only: open
                .requestMatchers("/api/admin/**").hasRole("ADMIN")  // admin only
                .anyRequest().authenticated()                      // everything else: needs JWT
            )
            .addFilterBefore(jwtAuthFilter, UsernamePasswordAuthenticationFilter.class)
            .build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public AuthenticationManager authManager(AuthenticationConfiguration config) throws Exception {
        return config.getAuthenticationManager();
    }
}
```

concept_explanation.jwt_service:
**JwtService — token generation and validation:**

```java
import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import java.security.Key;
import java.util.*;

@Service
public class JwtService {

    @Value("${jwt.secret}")
    private String secret;  // 256-bit hex string from application.properties

    @Value("${jwt.expiration:86400000}")  // default: 24 hours in ms
    private long expirationMs;

    private Key getSigningKey() {
        return Keys.hmacShaKeyFor(Base64.getDecoder().decode(secret));
    }

    // Generate a JWT for a user:
    public String generateToken(String username, List<String> roles) {
        return Jwts.builder()
            .subject(username)
            .claim("roles", roles)
            .issuedAt(new Date())
            .expiration(new Date(System.currentTimeMillis() + expirationMs))
            .signWith(getSigningKey())
            .compact();
    }

    // Extract username from token:
    public String extractUsername(String token) {
        return Jwts.parser()
            .verifyWith((SecretKey) getSigningKey())
            .build()
            .parseSignedClaims(token)
            .getPayload()
            .getSubject();
    }

    // Validate token (not expired, signature valid):
    public boolean isValid(String token, UserDetails userDetails) {
        try {
            String username = extractUsername(token);
            Claims claims = Jwts.parser()
                .verifyWith((SecretKey) getSigningKey())
                .build().parseSignedClaims(token).getPayload();
            return username.equals(userDetails.getUsername())
                && claims.getExpiration().after(new Date());
        } catch (JwtException e) {
            return false;  // expired, tampered, or invalid
        }
    }
}
```

concept_explanation.jwt_filter:
**JwtAuthFilter — intercepts every request:**

```java
import org.springframework.security.authentication.*;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

@Component
public class JwtAuthFilter extends OncePerRequestFilter {

    private final JwtService jwtService;
    private final UserDetailsService userDetailsService;

    JwtAuthFilter(JwtService j, UserDetailsService u) {
        jwtService = j; userDetailsService = u;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain)
            throws ServletException, IOException {

        // 1. Extract token from Authorization header:
        String authHeader = request.getHeader("Authorization");
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            filterChain.doFilter(request, response);  // no token → pass through
            return;
        }

        String token = authHeader.substring(7);  // remove 'Bearer '

        // 2. Extract username from token:
        String username = jwtService.extractUsername(token);

        // 3. If username found and not already authenticated:
        if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
            UserDetails userDetails = userDetailsService.loadUserByUsername(username);

            // 4. Validate token:
            if (jwtService.isValid(token, userDetails)) {
                // 5. Set authentication in SecurityContext:
                var authToken = new UsernamePasswordAuthenticationToken(
                    userDetails, null, userDetails.getAuthorities());
                SecurityContextHolder.getContext().setAuthentication(authToken);
            }
        }

        filterChain.doFilter(request, response);  // continue the chain
    }
}
```

concept_explanation.auth_controller:
**AuthController — login endpoint:**

```java
@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthenticationManager authManager;
    private final JwtService jwtService;
    private final UserDetailsService userDetailsService;

    // ... constructor ...

    public record LoginRequest(String username, String password) {}
    public record AuthResponse(String token, String username, List<String> roles) {}

    @PostMapping("/login")
    public ResponseEntity<AuthResponse> login(@RequestBody LoginRequest req) {
        // Spring Security verifies credentials:
        authManager.authenticate(
            new UsernamePasswordAuthenticationToken(req.username(), req.password()));

        // If we get here, credentials were valid:
        UserDetails user = userDetailsService.loadUserByUsername(req.username());
        List<String> roles = user.getAuthorities().stream()
            .map(a -> a.getAuthority()).toList();
        String token = jwtService.generateToken(req.username(), roles);

        return ResponseEntity.ok(new AuthResponse(token, req.username(), roles));
    }
}
```

