@Entity
public class AppUser {
    @Id @GeneratedValue(strategy = GenerationType.UUID) private String id;
    @Column(unique = true, nullable = false) private String username;
    @Column(nullable = false) private String password;  // BCrypt hashed
    @Column(nullable = false) private String role;      // ROLE_USER or ROLE_ADMIN
    // constructors, getters...
}

@Service
public class AppUserDetailsService implements UserDetailsService {
    private final AppUserRepository repo;
    AppUserDetailsService(AppUserRepository r) { repo = r; }

    @Override
    public UserDetails loadUserByUsername(String username) {
        AppUser user = repo.findByUsername(username)
            .orElseThrow(() -> new UsernameNotFoundException("User not found: " + username));
        return User.builder()
            .username(user.getUsername())
            .password(user.getPassword())
            .roles(user.getRole())  // ROLE_ prefix added automatically
            .build();
    }
}
